// 1. Get the raw text string from the Architect Node
const rawText = $input.item.json.candidates[0].content.parts[0].text;

// 2. Clean the text (Remove markdown wrappers if the AI added them)
const cleanText = rawText.replace(/```json|```/g, '').trim();

// 3. Parse it into a real Object
let parsedStrategy;
try {
  parsedStrategy = JSON.parse(cleanText);
} catch (error) {
  // Fallback if AI output bad JSON (Rare, but good safety)
  parsedStrategy = { error: "Failed to parse JSON", raw: rawText };
}

// 4. Return the merged result
// We keep the original job data + add the new strategy
return {
  json: {
    ...$input.item.json,
    resume_strategy: parsedStrategy
  }
};

