parameters.jsCode:
// 1. Get Inputs
const vault = $('Resume_Vault').item.json;
const strategyItem = $('Parse_Architect_Response').item;
const strategy = strategyItem ? strategyItem.json.resume_strategy : {};
const builder = strategy.builder || {};

// 2. Build the Header (ATS Optimized & Reordered: LinkedIn -> Email -> Phone -> Location)
const headerHtml = `
  <div class="header">
    <h1>${vault.my_name}</h1>
    <div class="sub-header">${builder.tailored_title || "BUSINESS SYSTEMS SPECIALIST (AUTOMATION & AI)"}</div>
    <div class="contact-info">
      <a href="${vault.my_linkedin}">LinkedIn</a> | 
      <a href="mailto:${vault.my_email}">${vault.my_email}</a> | 
      <a href="tel:${vault.my_phone.replace(/\+/g, '')}">${vault.my_phone}</a> | 
      ${vault.my_location}
    </div>
  </div>`;

// 3. Build Summary (Dynamic Replacement)
let summaryHtml = "";
if (vault.blocks.professional_identity) {
    summaryHtml = vault.blocks.professional_identity.replace(
        /<p>[\s\S]*?<\/p>/, 
        `<p>${builder.tailored_identity_text || "Backend automation engineer who builds autonomous business systems that protect and generate revenue. I architect self-healing logic layers that enforce business rules, detect financial leaks, and scale operations without adding headcount."}</p>`
    );
}

// 4. Build Projects (Formatted as PROFESSIONAL EXPERIENCE, strict ordering, NO numbers)
let projectsHtml = "<h2>PROFESSIONAL EXPERIENCE</h2>";

if (builder.project_order && Array.isArray(builder.project_order)) {
    builder.project_order.forEach((item) => {
        // Handle if AI returns object {id: "..."} or just string "..."
        const id = typeof item === 'object' ? item.id : item;
        let blockHtml = vault.blocks[id];

        if (blockHtml) {
            projectsHtml += blockHtml;
        }
    });
} else {
    // Fallback: Default order with no numbering
    vault.project_list.forEach((id) => {
         if(vault.blocks[id]) {
             projectsHtml += vault.blocks[id];
         }
    });
}

// 5. CSS Styles - The "98-Score ATS" Polish
const css = `
<style>
  /* Page constraints to fit content cleanly */
  @page {
    margin: 0.75in; 
    size: A4;
  }

  body { 
    font-family: 'Arial', 'Helvetica', sans-serif; /* Safest ATS font */
    color: #000; 
    line-height: 1.35; 
    padding: 0; 
    margin: 0 auto; 
    font-size: 10pt; /* Reduced to fit more content elegantly */
  }

  /* Clean Header */
  .header { 
    text-align: center; 
    margin-bottom: 16px; 
  }
  h1 { 
    font-size: 20pt; 
    font-weight: bold; 
    text-transform: uppercase; 
    margin: 0 0 4px 0; 
    letter-spacing: 0.5px; 
  }
  .sub-header { 
    font-size: 11pt; 
    font-weight: bold; 
    text-transform: uppercase; 
    margin-bottom: 4px;
  }
  .contact-info { 
    font-size: 9.5pt; 
  }
  a { 
    color: #000; 
    text-decoration: none; 
  }

  /* Section Headings - The classic ATS underline */
  h2 { 
    font-size: 11pt; 
    font-weight: bold; 
    text-transform: uppercase; 
    margin-top: 14px; 
    margin-bottom: 8px;
    padding-bottom: 2px;
    border-bottom: 1px solid #000; 
  }

  p { 
    margin: 0 0 10px 0; 
    text-align: left; /* Left align is safer for ATS parsers than justify */
  }

  /* Skills Section */
  .competencies { 
    margin-bottom: 4px; 
    font-size: 10pt; 
    line-height: 1.4;
  }
  .comp-label { 
    font-weight: bold; 
  }

  /* Experience Blocks */
  .section-block { 
    margin-bottom: 14px; 
    page-break-inside: avoid; 
  }
  .project-title { 
    font-weight: bold; 
    text-transform: uppercase; 
    font-size: 10.5pt; 
  }
  .project-role { 
    font-style: italic; 
    margin-top: 2px;
    margin-bottom: 4px; 
    font-size: 10pt; 
  }

  /* Clean Bullet Points */
  ul.bullet-list { 
    margin: 0 0 0 0; 
    padding-left: 18px; 
  }
  li { 
    margin-bottom: 3px; 
  }
</style>
`;

// 6. Assemble Final HTML
const finalHtml = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  ${css}
</head>
<body>
  ${headerHtml}
  ${summaryHtml}
  ${vault.blocks.core_competencies || ''}
  ${vault.blocks.technical_stack || ''}
  ${projectsHtml}
  ${vault.blocks.experience || ''}
  ${vault.blocks.education || ''}
</body>
</html>
`;

// 7. Return Result
return {
  json: {
    html_content: finalHtml,
    filename: `Resume_Faith_Leke-Akingboye_${(builder.tailored_title || 'Resume').replace(/[^a-zA-Z0-9]/g, '_')}`
  }
};

const item = $input.item.json;

// --- SAFETY CHECK START ---
// (This just stops the crash if Gemini sends back nothing)
if (!item.candidates || !item.candidates[0] || !item.candidates[0].content) {
  return {
    json: {
      ...item,
      ai_analysis: { is_valid_role: false, primary_reason: "API_FAILURE" }
    }
  };
}
// --- SAFETY CHECK END ---

try {
  // === YOUR ORIGINAL LOGIC IS HERE ===
  // 1. Get the raw text
  const rawText = item.candidates[0].content.parts[0].text;

  // 2. Clean the text (Identical to yours)
  const cleanText = rawText.replace(/```json|```/g, '').trim();

  // 3. Parse it (Identical to yours)
  const parsedDecision = JSON.parse(cleanText);

  // 4. Return the result (Identical to yours)
  return {
    json: {
      ...item, // Keeps all original job data
      ai_analysis: parsedDecision
    }
  };
  // === END OF YOUR LOGIC ===

} catch (error) {
  // --- SAFETY NET START ---
  // If the JSON parse fails, we just say "It's not a fit" instead of crashing
  return {
    json: {
      ...item,
      ai_analysis: { is_valid_role: false, primary_reason: "BAD_JSON" }
    }
  };
  // --- SAFETY NET END ---
}

// 1. Get the incoming text from Telegram safely
const messageText = $input.item.json.message?.text || "";

// 2. Define the Pattern: Look for http:// or https:// followed by non-space characters
const urlRegex = /(https?:\/\/[^\s]+)/;
const match = messageText.match(urlRegex);

// 3. Logic: Did we find a link?
if (match && match[0]) {
  // ✅ Link Found: Output ONLY the extraction data
  return {
    json: {
      job_url: match[0],        // The URL we found
      has_valid_link: true      // Flag for the Switch Node
    }
  };
} else {
  // ❌ No Link: Output the failure flag
  return {
    json: {
      has_valid_link: false     // Flag for the Switch Node
    }
  };
}

// CONFIGURATION
const DAILY_LIMIT = 19; 

const allKeys = $input.all();

// 1. FILTER & TYPE SAFETY
const validKeys = allKeys.filter(item => {
    // Force convert to Integer. If invalid/null, default to 0.
    const rawUsage = item.json.Daily_Usage;
    const currentUsage = parseInt(rawUsage, 10) || 0;

    // Store the clean number back in the item for step 3
    item.cleanUsage = currentUsage;

    return currentUsage < DAILY_LIMIT;
});

// 2. CRITICAL STOP
if (validKeys.length === 0) {
    throw new Error(`⛔ STOP: All ${allKeys.length} keys are exhausted (Usage >= ${DAILY_LIMIT}). Reset Baserow counts.`);
}

// 3. SELECTION
const randomIndex = Math.floor(Math.random() * validKeys.length);
const selectedKey = validKeys[randomIndex];

// 4. OUTPUT
return {
    json: {
        selected_api_key: selectedKey.json.API_Key,
        row_id: selectedKey.json.id,
        // Safe Math: Guaranteed to be a number + 1
        new_usage_count: selectedKey.cleanUsage + 1,
        key_name: selectedKey.json.Name || "Unknown Key"
    }
};
